VALUES
  ('pukao-8b44517b-moex-00296', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '關於都市計畫之行政爭訟，依現行行政訴訟法之規定，下列敘述何者正確？', '["凡依都市計畫法發布之都市計畫，皆得為行政法院審查之標的", "都市計畫審查程序中，擬定及核定都市計畫之機關，共同為被告機關", "都市計畫審查程序，專屬都市計畫區所在地之地方法院行政訴訟庭管轄", "行政法院審查如認都市計畫違法，應判決原告有理由，並撤銷該都市計畫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00297', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '甲主張行政處分無效，向行政法院提起確認行政處分無效訴訟。依行政訴訟法之規定，下列敘述何者 正確？', '["甲提起之確認行政處分無效訴訟，並無應遵守之法定起訴期間規定", "甲應依訴願法提起訴願而不服其決定，始得提起確認行政處分無效訴訟", "如甲得提起撤銷訴訟或課予義務訴訟，不得提起確認行政處分無效訴訟", "如行政法院認為甲應提起課予義務訴訟，應裁定訴願管轄機關補提答辯狀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00298', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '下列何者非屬以地方法院行政訴訟庭為第一審管轄法院之事件？', '["依入出國及移民法提起之收容異議事件", "請求判命行政機關應作成依法申請之建造執照", "請求撤銷依道路交通管理處罰條例作成之裁決", "請求確認行政機關所為新臺幣40萬元以下罰鍰處分為無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00299', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '依國家賠償法之規定，關於國家賠償請求權之行使，下列敘述何者正確？', '["請求權人限於權利受損害之自然人，不包括法人", "因公務員行為所生之國家賠償責任，賠償義務人為從事該行為之公務員", "請求權人如未經協議程序，即向法院提起國家賠償訴訟，該訴訟不合法", "國家賠償之訴訟，除依國家賠償法之規定外，應準用行政訴訟法之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00300', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '甲之三合院古厝，長期出租他人作為廠房使用。嗣主管機關依法將其列為暫定古蹟，但因承租人之營 運可能破壞古蹟，致甲不得繼續出租。甲得基於下列何者，請求主管機關彌補其租金收益損失？', '["公法上不當得利返還請求權", "損失補償請求權", "國家賠償請求權", "公法上無因管理之管理費用請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00301', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '關於徵收補償之敘述，下列何者正確？', '["須為合法公權力措施", "適用第一次權利保護優先原則", "當事人無須構成特別犧牲", "原公權力措施得預見其附帶違法侵害效果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00302', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '關於國家賠償法第3條公共設施之敘述，下列何者錯誤？', '["縱使尚未驗收合格之公共設施，如已開放公眾使用，仍有國家賠償法之適用", "公共設施之開放使用係屬行政機關事實行為", "私人所有之公共設施，亦有國家賠償法之適用", "公共設施設置地點之選定，屬公權力行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8ec6300d-moex-00001', 'pukao-8ec6300d', 'pukao-8ec6300d-moex-114-156cbda0', 'sub-pukao-8ec6300d-01', NULL, 'single_choice', '十六進制數字54B，等同那一個十進制數字？', '["927", "1282", "1355", "1764"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:41+00:00", "source_pdf_sha1": "ebba180acb37", "answer_pdf_sha1": "b58c95b8bfaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "447", "s": "2504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "電信工程"}'::jsonb, NULL),
  ('pukao-8ec6300d-moex-00002', 'pukao-8ec6300d', 'pukao-8ec6300d-moex-114-156cbda0', 'sub-pukao-8ec6300d-01', NULL, 'single_choice', '假設有一台電腦的記憶體容量為512MB（Megabytes），每一筆資料會用16bytes的單位來儲存資料，至少 需要多少位元數（bits）來定位記憶體中的任何一筆資料？', '["12位元", "16位元", "24位元", "32位元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:41+00:00", "source_pdf_sha1": "ebba180acb37", "answer_pdf_sha1": "b58c95b8bfaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "447", "s": "2504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "電信工程"}'::jsonb, NULL),
  ('pukao-8ec6300d-moex-00003', 'pukao-8ec6300d', 'pukao-8ec6300d-moex-114-156cbda0', 'sub-pukao-8ec6300d-01', NULL, 'single_choice', '關於算術／邏輯指令（Arithmetic／LogicInstructions）的敘述，下列何者正確？', '["算術／邏輯指令的功能是將資料從CPU傳送至主記憶體", "包括布林邏輯運算，例如AND、OR及XOR等", "包含從記憶體載入資料到暫存器的動作", "可用於控制程式流程，例如條件式跳躍（ConditionalJump）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:41+00:00", "source_pdf_sha1": "ebba180acb37", "answer_pdf_sha1": "b58c95b8bfaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "447", "s": "2504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "電信工程"}'::jsonb, NULL)
